const uid = () => Date.now().toString(36) + Math.random().toString(36).slice(2,6);

const WK = ["2026-05-18","2026-05-25","2026-06-01","2026-06-08","2026-06-15"];
const today = ()=> new Date().toISOString().slice(0,10);
function seedHash(s){ let h=0; for(let i=0;i<(s||"").length;i++){ h=(h*31+s.charCodeAt(i))>>>0; } return h; }
function genHistory(p){
  const price = ((p.vendors||[]).find(v=>v.primary)||(p.vendors||[])[0]||{}).price;
  const h = seedHash(p.name); const base = 1 + (h%6);
  let count = base*2 + (h%4); const hist=[];
  for(let i=0;i<WK.length;i++){
    let used = Math.max(0, base + ((seedHash(p.name+i)%3)-1));
    if(i===WK.length-1 && h%5===0) used = Math.round(used*2.4);
    let received = Math.max(0, used + ((seedHash(p.name+"r"+i)%3)-1));
    let unitCost = price!=null ? +(price/(p.countPerCase||1)).toFixed(2) : null;
    if(unitCost!=null && i===WK.length-1 && h%4===0) unitCost = +(unitCost*1.12).toFixed(2);
    let newCount = count + received - used;
    if(i===2 && h%7===0) newCount = count + received + 2;
    newCount = Math.max(0, newCount);
    used = count + received - newCount;
    hist.push({wk:WK[i], count:newCount, received, used, unitCost});
    count = newCount;
  }
  return hist;
}
function lastSnap(p){ const h=p.history||[]; return h[h.length-1]||null; }
function prevSnap(p){ const h=p.history||[]; return h[h.length-2]||null; }
function ensureByLoc(snap, p){ if(snap && snap.byLoc) return {...snap.byLoc}; const prim=(p.locations||[]).find(l=>l.primary)?.name || (p.locations||[])[0]?.name || "Unassigned"; return { [prim]: {cases:0, loose:0, count:(snap&&snap.count)||0} }; }
function priorWeekUsage(p){ const s=lastSnap(p); return s?s.used:0; }
function avg4(p){ const h=(p.history||[]).slice(-4); if(!h.length) return 0; return h.reduce((a,b)=>a+b.used,0)/h.length; }
function latestUnitCost(p){ const h=(p.history||[]).filter(x=>x.unitCost!=null); return h.length?h[h.length-1].unitCost:costPerCount(p); }
function prevUnitCost(p){ const h=(p.history||[]).filter(x=>x.unitCost!=null); return h.length>1?h[h.length-2].unitCost:null; }
function flagsFor(p){
  const out=[]; const s=lastSnap(p); if(!s) return out; const a=avg4(p);
  if(s.used<0) out.push({p,kind:"miscount",text:`Negative usage (${s.used}) — likely a miscount or an unlogged delivery. Recount and confirm receipts.`});
  else if(a>0 && s.used>a*2) out.push({p,kind:"spike",text:`Usage jumped to ${s.used} ${p.useUnit==="each"?"ct":p.countUnit} vs a ${a.toFixed(1)} average. Check against sales for waste, over-portioning, or shrink.`});
  const pc=prevUnitCost(p), lc=latestUnitCost(p);
  if(pc!=null && lc!=null && lc>pc*1.08) out.push({p,kind:"price",text:`Cost up ${(((lc-pc)/pc)*100).toFixed(0)}% (${money(pc)}→${money(lc)} per ${p.countUnit}). Worth comparing vendors.`});
  if(s.count>0 && a>0 && s.count<a) out.push({p,kind:"low",text:`On hand (${s.count}) is under one week of usage (${a.toFixed(1)}). Add to the shopping list.`});
  return out;
}

