const money = (n) => (n == null || isNaN(n)) ? "—" : "$" + Number(n).toFixed(2);
const num = (v) => { const n = parseFloat(v); return isNaN(n) ? null : n; };

function costPerCount(p){ const c = p.vendors?.find(v=>v.primary)?.price ?? p.vendors?.find(v=>v.price!=null)?.price; if(c==null||!p.countPerCase) return null; return c / p.countPerCase; }
function costPerUse(p){ const cc = costPerCount(p); if(cc==null||!p.usePerCount) return null; return cc / p.usePerCount; }
function bestVendor(p){ const priced = (p.vendors||[]).filter(v=>v.price!=null); if(priced.length<2) return null; return priced.reduce((a,b)=>b.price<a.price?b:a); }
function primaryVendor(p){ return (p.vendors||[]).find(v=>v.primary) || (p.vendors||[])[0]; }
function locLabel(p){ const ls=(p.locations||[]); if(!ls.length) return "No location"; const prim=ls.find(l=>l.primary)||ls[0]; const rest=ls.filter(l=>l!==prim); return rest.length ? `${prim.name} · ${rest.map(r=>r.name).join(" · ")}` : prim.name; }

const SONNET = "claude-sonnet-4-6";
function fileToB64(file){ return new Promise((res,rej)=>{ const r=new FileReader(); r.onload=()=>res(r.result.split(",")[1]); r.onerror=()=>rej(new Error("read")); r.readAsDataURL(file); }); }
async function readBarcodeFromImage(file){
  if(!("BarcodeDetector" in window)) return null;
  try{ const det=new window.BarcodeDetector(); const bmp=await createImageBitmap(file); const codes=await det.detect(bmp); return codes?.[0]?.rawValue||null; }catch{ return null; }
}
async function callVision(file, prompt){
  const b64 = await fileToB64(file);
  const resp = await fetch("https://api.anthropic.com/v1/messages",{ method:"POST", headers:{"Content-Type":"application/json"},
    body: JSON.stringify({ model:SONNET, max_tokens:1000, messages:[{role:"user",content:[
      {type:"image",source:{type:"base64",media_type:file.type||"image/jpeg",data:b64}},{type:"text",text:prompt}]}]}) });
  const data = await resp.json();
  const text = (data.content||[]).filter(b=>b.type==="text").map(b=>b.text).join("\n");
  return JSON.parse(text.replace(/```json|```/g,"").trim());
}
async function identifyFromImage(file){
  return callVision(file, `Identify the single food-service product shown (a box, bag, can, or label). Return ONLY JSON, no markdown: {"name":string,"brand":string,"supc":string,"barcode":string (the digits printed beneath a barcode if clearly readable, else ""),"category":one of ${JSON.stringify(CATS)} or ""}. Do not guess a barcode if none is clearly readable. Output JSON only.`);
}
function buildProductFromVision(d){
  return { id:uid(), name:d.name||"", category:CATS.includes(d.category)?d.category:"",
    brand:d.brand||"", supc:d.supc||"", purchaseUnit:d.purchaseUnit||"Case",
    pack:d.pack||1, size:d.size||"", sizeUnit:d.sizeUnit||"",
    countUnit:d.countUnit||"each", countPerCase:d.countPerCase||d.pack||1,
    useUnit:d.useUnit||"each", usePerCount:d.usePerCount??null,
    barcodes: d.barcode ? [String(d.barcode)] : [],
    locations:[{name: CAT_LOCATION[CATS.includes(d.category)?d.category:""] || "Back Kitchen", primary:true}],
    vendors:[{name:VENDORS.includes(d.vendorName)?d.vendorName:"Sysco", price:d.price??null, primary:true}] };
}
const tok = (s)=>(s||"").toLowerCase().replace(/[^a-z0-9 ]/g," ").split(/\s+/).filter(Boolean);
function matchProducts(catalog, {barcode,supc,name,brand}){
  const code = (barcode||supc||"").trim();
  if(code){ const hit = catalog.filter(p => (p.barcodes||[]).includes(code) || (p.supc && p.supc===code)); if(hit.length) return {exact:true,candidates:hit}; }
  const want = new Set([...tok(name),...tok(brand)]);
  if(!want.size) return {exact:false,candidates:[]};
  const scored = catalog.map(p=>{ const have=new Set([...tok(p.name),...tok(p.brand)]); let s=0; want.forEach(t=>{ if(have.has(t)) s++; }); return {p,s}; })
    .filter(x=>x.s>0).sort((a,b)=>b.s-a.s);
  return {exact:false,candidates:scored.slice(0,4).map(x=>x.p)};
}

